const ocrResponse = $('Claude Vision OCR').first().json;
const participant = $('Obtener Participante').first().json;
const input = $('Validar Input').first().json;

let ocr = {};
try {
  const text = ocrResponse?.content?.[0]?.text || '{}';
  const cleaned = text.replace(/```json\n?|```/g, '').trim();
  ocr = JSON.parse(cleaned);
} catch(e) {
  ocr = { confianza: 0.0, motivo_baja_confianza: 'No se pudo parsear respuesta OCR' };
}

const confianza = parseFloat(ocr.confianza) || 0.0;
const esProductoValido = ocr.es_producto_valido === true;
const fechaOk = !!ocr.fecha_compra;

// Presentaciones validas configurables (env PRESENTACIONES_VALIDAS, separadas por coma; vacio o * = cualquiera)
const presRaw = ($env.PRESENTACIONES_VALIDAS || '').trim();
const presValidas = presRaw.split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
const pres = (ocr.presentacion || '').trim().toLowerCase();
const esPresentacionValida = presRaw === '' || presRaw === '*' || presValidas.includes(pres);

const CONFIANZA_MIN = parseFloat($env.OCR_CONFIANZA_MINIMA) || 0.70;
const pasaAuto = confianza >= CONFIANZA_MIN && esProductoValido && esPresentacionValida && fechaOk;

let motivo = null;
if (!pasaAuto) {
  const razones = [];
  if (confianza < CONFIANZA_MIN) razones.push(`Confianza OCR baja (${Math.round(confianza*100)}%)`);
  if (!esProductoValido) razones.push('Producto no identificado como Mobil Delvac');
  if (!esPresentacionValida) razones.push(`Presentacion "${ocr.presentacion || '?'}" no participante`);
  if (!fechaOk) razones.push('Fecha de compra no legible');
  motivo = razones.join('; ');
}

return [{ json: {
  participant_id: participant?.id,
  phone: input.phone,
  media_url: input.media_url,
  ocr,
  confianza,
  pasaAuto: pasaAuto ? 'true' : 'false',
  motivo,
  estado: pasaAuto ? 'aprobada_auto' : 'en_revision',
} }];

const ev = $('Evaluar OCR').first().json;
return [{ json: {
  ok: 'true',
  resultado: ev.estado,
  pasa_auto: ev.pasaAuto,
  motivo: ev.motivo,
  mensaje: ev.pasaAuto === 'true'
    ? '¡Tu factura fue verificada exitosamente! Tu registro en el Gran Premio Mobil Delvac 2026 está COMPLETO. 🏁'
    : 'Recibimos tu factura y está siendo revisada por nuestro equipo. Te notificaremos en máximo 24 horas. ⏳',
} }];
